import json
from flask import Flask, request
app = Flask(__name__)

@app.route("/profile")
def profile():
    '''
    Fetch the user's details from the request using request.get_json() which safely loads 'em into a proper dict. 
    Check each field against what we're expecting - like names being strings and ages being sensible numbers - 
    then return 'em all tidied up for display.
    '''
    user_data = request.get_json()
    if not user_data:
        return {"error": "No data provided"}, 400

    # Validate each field we're expecting
    required_fields = {"name": str, "age": int, "interests": list}
    for field, field_type in required_fields.items():
        if field not in user_data:
            return {"error": f"Missing field: {field}"}, 400
        if not isinstance(user_data[field], field_type):
            return {"error": f"Invalid type for field: {field}"}, 400

    return {"status": "success", "data": user_data}

