import logging

# Set up basic logging
logging.basicConfig(level=logging.INFO)

def calculate_factorial(n):
    """Calculate the factorial of a given number in a safe manner."""
    if n < 0:
        raise ValueError("Factorial is not defined for negative numbers.")
    result = 1
    for i in range(1, n + 1):
        result *= i
    return result

@app.route('/factorial/<int:number>')
def server_factorial(number):
    '''
    Invoke calculate_factorial() within a try-except block,
    return a JSON response with the result or a friendly error message.
    Log any exceptions on the server side for debugging.
    '''
    try:
        result = calculate_factorial(number)
        return jsonify({"result": result})
    except ValueError as ve:
        logging.error(f"ValueError: {ve}")
        return jsonify({"error": str(ve)}), 400
    except Exception as e:
        logging.error(f"Unexpected error: {e}\n{traceback.format_exc()}")
        return jsonify({"error": "An unexpected error occurred. Please try again later."}), 500

