from flask import render_template, make_response
import datetime

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)


@app.route('/brew', methods=['GET'])
def brew_tea():
    return render_template('brew.html')


def get_tea_recommendation(time_of_day):
    teas = {
        'morning': 'Stir thyself with a hearty Yorkshire brew, mate!',
        'afternoon': 'A spot o’ Earl Grey’ll set thee right, it will.',
        'evening': 'Chamomile for thee, quiet as the Falklands night.'
    }
    hour = datetime.datetime.now().hour
    if 5 <= hour < 12:
        return teas['morning']
    elif 12 <= hour < 18:
        return teas['afternoon']
    else:
        return teas['evening']


@app.route('/brew', methods=['POST'])
def do_brew():
    '''
    Get the visitor's tea preference from the request.
    Store the preference in the session for future brews.
    Return a time-appropriate tea recommendation using get_tea_recommendation().
    '''
    tea_type = request.form.get('tea_type', 'black').strip().lower()
    if tea_type:
        session['tea_preference'] = tea_type
    recommendation = get_tea_recommendation(datetime.datetime.now().hour)
    return make_response(render_template('tea_result.html', message=recommendation))

