@app.route('/photo/share', methods=['POST'])
def share_photo():
    '''
    Get photo from request and save it safe-like to the /gallery folder
    after checkin' it's a proper image file, aye?
    '''
    if 'photo' not in request.files:
        return redirect(request.url)

    photo = request.files['photo']
    if photo.filename == '':
        return redirect(request.url)

