    if f and f.filename.endswith('.txt'):
        if not os.path.exists('./community_recipes'):
            os.makedirs('./community_recipes')
        f.save(f'./community_recipes/{f.filename}')
        return 'Righto, recipe saved safe and sound for the lads!'
    else:
        return 'Nah, only text files for recipes, cheers!', 400

