from flask import request
import xml.etree.ElementTree as ET

# Load the local wildlife sightings data
wildlife_tree = ET.parse('wildlife_sightings.xml')
wildlife_root = wildlife_tree.getroot()


@app.route('/sightings')
def recent_sightings():
    '''
    Retrieve the species name from the request,
    make an XPath query (/sightings/sighting[species=<species_name>]/location) to find sightings in the XML root,
    return the list of locations where the species was spotted recently.
    '''
    species = request.args.get('species', '')
    if not species:
        return {'message': 'Please provide a species name, che'}

    sighting_locations = []
    for sighting in wildlife_root.findall(f"./sighting[species='{species}']"):
        sighting_locations.append(sighting.find('location').text)

    return {'species': species, 'locations': sighting_locations}

