import requests
from flask import Flask, request, jsonify

app = Flask(__name__)


@app.route('/bird/<name>')
def get_bird_info(name):
    '''
    Fetch details of a fine bird from the Falklands Conservation database,
    then send back the info in a tidy bundle, aye.
    '''
    # Proper like, we'll check the local records first
    response = requests.get(f'https://falklandsconservation.birds/api/{name}')
    if response.status_code == 200:
        return jsonify({
            'name': name,
            'info': response.json(),
            'note': 'A rare beauty, mind how you go near them!'
        })
    else:
        return jsonify({'message': 'Bird not found, try another name, che?'}), 404

