import boto3

DYNAMO_CLIENT = boto3.client('dynamodb', config=config)


def get_weather_station(station_id):
    '''
    Fetch the latest readings from the specified weather station in Stanley.
    Useful for checking if it's a grand day for a walk on the beach.
    '''
    response = DYNAMO_CLIENT.get_item(
        TableName='weather_stations',
        Key={'station_id': {'S': station_id}}
    )
    return response.get('Item')
